import React from 'react';
import { PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const COLORS = {
  Entertainment: '#6366f1',
  Utilities: '#f59e0b',
  Health: '#10b981',
  Software: '#3b82f6',
  Food: '#ef4444',
  Other: '#8b5cf6'
};

export default function CategoryPieChart({ byCategory = {} }) {
  const data = Object.entries(byCategory)
    .filter(([_, value]) => value > 0)
    .map(([name, value]) => ({ name, value }));

  const CustomTooltip = ({ active, payload }) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-[#12121a] border border-[#1e1e2e] p-3 rounded-xl shadow-lg">
          <p className="text-gray-300 text-sm mb-1">{payload[0].name}</p>
          <p className="text-white font-bold">Γé╣{payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-[#12121a] border border-[#1e1e2e] rounded-2xl p-6 shadow-lg hover:shadow-indigo-500/10 transition-all duration-300 h-[400px] flex flex-col">
      <h3 className="text-xl font-bold text-white mb-4">Spend by Category</h3>
      {data.length === 0 ? (
        <div className="flex-1 flex items-center justify-center text-gray-500">No category data available</div>
      ) : (
        <div className="flex-1 min-h-0 w-full relative">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={data}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
                stroke="none"
              >
                {data.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[entry.name] || COLORS.Other} />
                ))}
            </Pie>
            <Tooltip content={<CustomTooltip />} cursor={{fill: 'transparent'}} />
            <Legend verticalAlign="bottom" height={36} wrapperStyle={{paddingTop: '20px'}} />
          </PieChart>
        </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';

const PRELOADED = [
  { id: 1, name: "Netflix", emoji: "≡ƒÄ¼", category: "Entertainment", suggestedAmount: 649 },
  { id: 2, name: "Spotify", emoji: "≡ƒÄ╡", category: "Entertainment", suggestedAmount: 119 },
  { id: 3, name: "Amazon Prime", emoji: "≡ƒôª", category: "Entertainment", suggestedAmount: 299 },
  { id: 4, name: "Hotstar", emoji: "Γ¡É", category: "Entertainment", suggestedAmount: 299 },
  { id: 5, name: "Jio Cinema", emoji: "≡ƒÄÑ", category: "Entertainment", suggestedAmount: 149 },
  { id: 6, name: "YouTube Premium", emoji: "Γû╢∩╕Å", category: "Entertainment", suggestedAmount: 189 },
  { id: 7, name: "Apple Music", emoji: "≡ƒìÄ", category: "Entertainment", suggestedAmount: 99 },
  { id: 8, name: "Gym Membership", emoji: "≡ƒÆ¬", category: "Health", suggestedAmount: 800 },
  { id: 9, name: "Swiggy Instamart", emoji: "≡ƒ¢Æ", category: "Food", suggestedAmount: 149 },
  { id: 10, name: "Zepto Pass", emoji: "ΓÜí", category: "Food", suggestedAmount: 99 },
  { id: 11, name: "Microsoft 365", emoji: "≡ƒÆ╝", category: "Software", suggestedAmount: 420 },
  { id: 12, name: "Canva Pro", emoji: "≡ƒÄ¿", category: "Software", suggestedAmount: 499 },
  { id: 13, name: "Jio Postpaid", emoji: "≡ƒô▒", category: "Utilities", suggestedAmount: 399 },
  { id: 14, name: "Airtel Postpaid", emoji: "≡ƒôí", category: "Utilities", suggestedAmount: 349 }
];

const CATEGORIES = ["Entertainment", "Health", "Food", "Software", "Utilities", "Other"];
const FREQUENCIES = ["Rarely", "Sometimes", "Daily"];

export default function Checklist() {
  const navigate = useNavigate();
  const [subscriptions, setSubscriptions] = useState(PRELOADED.map(sub => ({ ...sub, selected: false, amount: sub.suggestedAmount, usageFrequency: '' })));
  const [customFormOpen, setCustomFormOpen] = useState(false);
  const [customData, setCustomData] = useState({ name: '', emoji: '≡ƒÆ│', amount: '', category: 'Other', usageFrequency: '' });
  const [errorToast, setErrorToast] = useState('');

  const handleToggle = (id) => {
    setSubscriptions(subs => subs.map(sub => sub.id === id ? { ...sub, selected: !sub.selected } : sub));
  };

  const handleUpdate = (id, field, value) => {
    setSubscriptions(subs => subs.map(sub => sub.id === id ? { ...sub, [field]: value } : sub));
  };

  const addCustomSubscription = () => {
    if (!customData.name || !customData.amount || !customData.usageFrequency) {
      showError('Please fill name, amount, and frequency for custom subscription');
      return;
    }
    const newSub = { 
      id: Date.now(), 
      ...customData, 
      amount: Number(customData.amount), 
      selected: true 
    };
    setSubscriptions([...subscriptions, newSub]);
    setCustomData({ name: '', emoji: '≡ƒÆ│', amount: '', category: 'Other', usageFrequency: '' });
    setCustomFormOpen(false);
  };

  const showError = (msg) => {
    setErrorToast(msg);
    setTimeout(() => setErrorToast(''), 3000);
  };

  const handleSubmit = async () => {
    const selected = subscriptions.filter(s => s.selected);

    if (selected.length === 0) {
      showError('Please select at least one subscription');
      return;
    }

    const invalid = selected.find(s => !s.amount || !s.usageFrequency);
    if (invalid) {
      showError(`Please fill amount and frequency for ${invalid.name}`);
      return;
    }

    const payload = selected.map(s => ({
      merchantName: s.name,
      amount: Number(s.amount),
      category: s.category,
      usageFrequency: s.usageFrequency.toLowerCase(),
      emoji: s.emoji
    }));

    const sessionId = localStorage.getItem('slasher_session_id');

    try {
      await api.post('/api/subscriptions/manual', { sessionId, subscriptions: payload });
      navigate('/dashboard');
    } catch (err) {
      showError('Failed to process subscriptions. Try again.');
      console.error(err);
    }
  };

  const selectedCount = subscriptions.filter(s => s.selected).length;
  const totalMonthly = subscriptions.filter(s => s.selected).reduce((acc, s) => acc + (Number(s.amount) || 0), 0);

  return (
    <div className="relative pb-32 max-w-5xl mx-auto">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-500 mb-2">Select your active subscriptions</h2>
        <p className="text-gray-400 text-lg">Click cards to add them to your vault</p>
      </div>

      {errorToast && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-50 bg-red-500/90 text-white px-6 py-3 rounded-lg shadow-lg font-medium animate-slide-up">
          {errorToast}
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
        {subscriptions.map((sub) => (
          <div 
            key={sub.id} 
            className={`bg-[#12121a] border rounded-2xl overflow-hidden transition-all duration-300 shadow-lg ${
              sub.selected ? 'border-indigo-500 shadow-indigo-500/20' : 'border-[#1e1e2e] hover:border-gray-600'
            }`}
          >
            <div 
              className="p-5 cursor-pointer flex items-center gap-4"
              onClick={() => handleToggle(sub.id)}
            >
              <div className="text-4xl bg-[#1e1e2e] w-14 h-14 rounded-xl flex items-center justify-center">
                {sub.emoji}
              </div>
              <div className="flex-1">
                <h3 className="font-bold text-lg text-white group-hover:text-indigo-400 transition-colors line-clamp-1">{sub.name}</h3>
                <p className="text-sm text-gray-400">Suggested: Γé╣{sub.suggestedAmount || sub.amount}/mo</p>
              </div>
              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${
                sub.selected ? 'bg-indigo-500 border-indigo-500' : 'border-gray-600'
              }`}>
                {sub.selected && <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
              </div>
            </div>

            {sub.selected && (
              <div className="px-5 pb-5 pt-2 border-t border-[#1e1e2e] bg-[#0d0d14] animate-fade-in flex flex-col gap-4">

                <div>
                  <label className="block text-xs text-gray-400 mb-1 uppercase tracking-wider font-semibold">Amount (Γé╣ / month)</label>
                  <input 
                    type="number" 
                    value={sub.amount} 
                    onChange={e => handleUpdate(sub.id, 'amount', e.target.value)}
                    className="w-full bg-[#12121a] border border-[#1e1e2e] focus:border-indigo-500 rounded-lg py-2 px-3 text-white outline-none transition-colors"
                  />
                </div>

                <div>
                  <label className="block text-xs text-gray-400 mb-2 uppercase tracking-wider font-semibold">Usage Frequency</label>
                  <div className="flex gap-2">
                    {FREQUENCIES.map(freq => (
                      <button
                        key={freq}
                        onClick={() => handleUpdate(sub.id, 'usageFrequency', freq)}
                        className={`flex-1 py-2 rounded-lg text-sm font-medium border transition-all ${
                          sub.usageFrequency === freq 
                            ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' 
                            : 'bg-[#12121a] border-[#1e1e2e] text-gray-400 hover:border-gray-500'
                        }`}
                      >
                        {freq}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-xs text-gray-400 mb-1 uppercase tracking-wider font-semibold">Category</label>
                  <select
                    value={sub.category}
                    onChange={e => handleUpdate(sub.id, 'category', e.target.value)}
                    className="w-full bg-[#12121a] border border-[#1e1e2e] focus:border-indigo-500 rounded-lg py-2 px-3 text-white outline-none transition-colors appearance-none"
                  >
                    {CATEGORIES.map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>

              </div>
            )}
          </div>
        ))}

        {/* Custom Input Block */}
        {!customFormOpen ? (
          <div 
            onClick={() => setCustomFormOpen(true)}
            className="bg-[#12121a] border border-dashed border-[#1e1e2e] hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer rounded-2xl flex flex-col items-center justify-center p-8 transition-all shadow-lg min-h-[140px]"
          >
            <div className="w-12 h-12 bg-[#1e1e2e] rounded-full flex items-center justify-center text-gray-400 mb-3 text-2xl group-hover:text-indigo-400">
              +
            </div>
            <p className="font-semibold text-gray-300">Add Custom Subscription</p>
          </div>
        ) : (
          <div className="bg-[#12121a] border border-indigo-500 rounded-2xl p-5 shadow-lg shadow-indigo-500/10 col-span-1 sm:col-span-2 lg:col-span-1 flex flex-col gap-4 animate-fade-in relative">
            <button onClick={() => setCustomFormOpen(false)} className="absolute top-4 right-4 text-gray-500 hover:text-white">&times;</button>
            <h3 className="font-semibold text-lg text-white mb-2">New Subscription</h3>

            <div className="flex gap-3">
              <div className="w-1/4">
                <input type="text" placeholder="≡ƒÆ│" className="w-full bg-[#0a0a0f] border border-[#1e1e2e] rounded-lg p-2 text-center text-xl outline-none" value={customData.emoji} onChange={e => setCustomData({...customData, emoji: e.target.value})} title="Emoji icon" />
              </div>
              <div className="flex-1">
                <input type="text" placeholder="Name (e.g., Notion)" className="w-full bg-[#0a0a0f] border border-[#1e1e2e] focus:border-indigo-500 rounded-lg p-2 text-white outline-none" value={customData.name} onChange={e => setCustomData({...customData, name: e.target.value})} />
              </div>
            </div>

            <div className="flex gap-3">
              <div className="w-1/2">
                <input type="number" placeholder="Γé╣ Amount/mo" className="w-full bg-[#0a0a0f] border border-[#1e1e2e] focus:border-indigo-500 rounded-lg p-2 text-white outline-none" value={customData.amount} onChange={e => setCustomData({...customData, amount: e.target.value})} />
              </div>
              <div className="w-1/2">
                <select className="w-full bg-[#0a0a0f] border border-[#1e1e2e] rounded-lg p-2 text-white outline-none appearance-none" value={customData.category} onChange={e => setCustomData({...customData, category: e.target.value})}>
                  {CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>
            </div>

            <div className="flex gap-1 justify-between">
              {FREQUENCIES.map(freq => (
                <button
                  key={freq}
                  onClick={() => setCustomData({...customData, usageFrequency: freq})}
                  className={`flex-1 py-1.5 px-2 rounded font-medium border text-xs transition-all ${
                    customData.usageFrequency === freq ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-[#0a0a0f] border-[#1e1e2e] text-gray-400 hover:border-gray-500'
                  }`}
                >
                  {freq}
                </button>
              ))}
            </div>

            <button onClick={addCustomSubscription} className="mt-2 w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 rounded-lg transition-colors">
              Add to List
            </button>
          </div>
        )}
      </div>

      {/* Sticky Bottom Bar */}
      <div className="fixed bottom-0 left-0 right-0 bg-[#0a0a0f]/80 backdrop-blur-xl border-t border-[#1e1e2e] p-4 lg:p-6 z-40 transform translate-y-0 transition-transform shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
        <div className="max-w-5xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-4">
          <div>
            <div className="text-gray-400 font-medium">
              <span className="text-white font-bold">{selectedCount}</span> subscriptions selected
            </div>
            <div className="text-sm">Total: <span className="text-emerald-400 font-bold text-lg hidden sm:inline-block absolute transform -translate-y-5 ml-2">Γé╣{totalMonthly}/month</span><span className="text-emerald-400 font-bold sm:hidden">Γé╣{totalMonthly}/month</span></div>
          </div>
          <button 
            onClick={handleSubmit}
            className="w-full sm:w-auto px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-bold rounded-xl shadow-lg ring-1 ring-white/20 transition-all hover:scale-105"
          >
            Analyse My Subscriptions &rarr;
          </button>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

export default function SubscriptionBarChart({ subscriptions = [] }) {
  // Take top 10 items to prevent chart clutter
  const data = [...subscriptions]
    .sort((a, b) => b.amount - a.amount)
    .slice(0, 10);

  const CustomTooltip = ({ active, payload }) => {
    if (active && payload && payload.length) {
      const dataPoint = payload[0].payload;
      return (
        <div className="bg-[#12121a] border border-[#1e1e2e] p-3 rounded-xl shadow-lg">
          <p className="text-white font-bold mb-1">{dataPoint.merchantName}</p>
          <p className="text-indigo-400 font-semibold mb-2">Γé╣{dataPoint.amount.toLocaleString()}</p>
          <div className="text-xs text-gray-400 capitalize bg-[#1e1e2e] px-2 py-1 rounded inline-block">
            {dataPoint.usageFrequency} usage
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-[#12121a] border border-[#1e1e2e] rounded-2xl p-6 shadow-lg hover:shadow-indigo-500/10 transition-all duration-300 h-[400px] flex flex-col">
      <h3 className="text-xl font-bold text-white mb-4">Subscription Breakdown</h3>
      {data.length === 0 ? (
        <div className="flex-1 flex items-center justify-center text-gray-500">No subscription data available</div>
      ) : (
        <div className="flex-1 min-h-0 w-full relative">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2d3748" vertical={false} />
              <XAxis 
                dataKey="merchantName" 
                tick={{fill: '#9ca3af', fontSize: 12}} 
                axisLine={{stroke: '#4b5563'}} 
                tickLine={false} 
                interval={0}
                angle={-45}
                textAnchor="end"
              />
              <YAxis 
                tick={{fill: '#9ca3af', fontSize: 12}} 
                axisLine={{stroke: '#4b5563'}} 
                tickLine={false} 
                tickFormatter={(val) => `Γé╣${val}`}
              />
              <Tooltip content={<CustomTooltip />} cursor={{fill: '#1e1e2e'}} />
              <Bar dataKey="amount" radius={[4, 4, 0, 0]}>
                {data.map((entry, index) => (
                  <Cell 
                    key={`cell-${index}`} 
                    fill={entry.usageFrequency === 'rarely' ? '#ef4444' : '#6366f1'} 
                  />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

